package com.example.auth

import android.content.Context
import android.content.Intent
import android.content.SharedPreferences
import android.os.Bundle
import android.widget.Button
import android.widget.EditText
import android.widget.TextView
import android.widget.Toast
import androidx.activity.ComponentActivity
import androidx.appcompat.app.AppCompatActivity
import androidx.biometric.BiometricManager
import androidx.biometric.BiometricPrompt
import androidx.core.content.ContextCompat

class AuthPrefs(context: Context) {
    private val prefs: SharedPreferences =
        context.getSharedPreferences("auth_prefs", Context.MODE_PRIVATE)

    fun isAuthenticated(): Boolean = prefs.getBoolean(KEY_AUTHENTICATED, false)

    fun setAuthenticated(value: Boolean) {
        prefs.edit().putBoolean(KEY_AUTHENTICATED, value).apply()
    }

    fun clearAuthentication() {
        prefs.edit().putBoolean(KEY_AUTHENTICATED, false).apply()
    }

    companion object {
        private const val KEY_AUTHENTICATED = "authenticated"
    }
}

class SplashOrLauncherActivity : AppCompatActivity() {
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)

        val authPrefs = AuthPrefs(this)

        if (authPrefs.isAuthenticated()) {
            startActivity(Intent(this, HomeActivity::class.java))
            finish()
        } else {
            startActivity(Intent(this, LoginActivity::class.java))
            finish()
        }
    }
}

class LoginActivity : ComponentActivity() {

    private lateinit var authPrefs: AuthPrefs
    private lateinit var passwordInput: EditText
    private lateinit var biometricButton: Button
    private lateinit var passwordButton: Button
    private lateinit var statusText: TextView

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_login)

        authPrefs = AuthPrefs(this)

        passwordInput = findViewById(R.id.passwordInput)
        biometricButton = findViewById(R.id.biometricButton)
        passwordButton = findViewById(R.id.passwordButton)
        statusText = findViewById(R.id.statusText)

        if (authPrefs.isAuthenticated()) {
            goToHome()
            return
        }

        biometricButton.setOnClickListener {
            startBiometricAuthentication()
        }

        passwordButton.setOnClickListener {
            verifyPasswordAndLogin()
        }

        updateBiometricAvailability()
    }

    private fun updateBiometricAvailability() {
        val biometricManager = BiometricManager.from(this)
        when (biometricManager.canAuthenticate(BiometricManager.Authenticators.BIOMETRIC_STRONG)) {
            BiometricManager.BIOMETRIC_SUCCESS -> {
                statusText.text = "Use fingerprint to sign in quickly, or enter your password."
                biometricButton.isEnabled = true
            }
            BiometricManager.BIOMETRIC_ERROR_NO_HARDWARE,
            BiometricManager.BIOMETRIC_ERROR_HW_UNAVAILABLE,
            BiometricManager.BIOMETRIC_ERROR_NONE_ENROLLED -> {
                statusText.text = "Fingerprint not available. Please sign in with your password."
                biometricButton.isEnabled = false
            }
            else -> {
                statusText.text = "Biometric sign-in unavailable. Please use your password."
                biometricButton.isEnabled = false
            }
        }
    }

    private fun startBiometricAuthentication() {
        val executor = ContextCompat.getMainExecutor(this)

        val promptInfo = BiometricPrompt.PromptInfo.Builder()
            .setTitle("Fingerprint Sign-In")
            .setSubtitle("Touch the fingerprint sensor to continue")
            .setDescription("Use your fingerprint for quick access, or cancel to use your password")
            .setNegativeButtonText("Use Password")
            .build()

        val biometricPrompt = BiometricPrompt(
            this,
            executor,
            object : BiometricPrompt.AuthenticationCallback() {
                override fun onAuthenticationSucceeded(result: BiometricPrompt.AuthenticationResult) {
                    super.onAuthenticationSucceeded(result)
                    authPrefs.setAuthenticated(true)
                    Toast.makeText(this@LoginActivity, "Fingerprint verified", Toast.LENGTH_SHORT).show()
                    goToHome()
                }

                override fun onAuthenticationError(errorCode: Int, errString: CharSequence) {
                    super.onAuthenticationError(errorCode, errString)
                    if (errorCode == BiometricPrompt.ERROR_NEGATIVE_BUTTON ||
                        errorCode == BiometricPrompt.ERROR_USER_CANCELED ||
                        errorCode == BiometricPrompt.ERROR_CANCELED
                    ) {
                        statusText.text = "Please enter your password to continue."
                    } else {
                        statusText.text = "Fingerprint failed. Please use your password."
                    }
                }

                override fun onAuthenticationFailed() {
                    super.onAuthenticationFailed()
                    statusText.text = "Fingerprint not recognized. Try again or use your password."
                }
            }
        )

        biometricPrompt.authenticate(promptInfo)
    }

    private fun verifyPasswordAndLogin() {
        val enteredPassword = passwordInput.text?.toString().orEmpty()

        if (enteredPassword.isBlank()) {
            Toast.makeText(this, "Please enter your password", Toast.LENGTH_SHORT).show()
            return
        }

        if (isValidPassword(enteredPassword)) {
            authPrefs.setAuthenticated(true)
            Toast.makeText(this, "Password verified", Toast.LENGTH_SHORT).show()
            goToHome()
        } else {
            authPrefs.clearAuthentication()
            Toast.makeText(this, "Incorrect password", Toast.LENGTH_SHORT).show()
        }
    }

    private fun isValidPassword(password: String): Boolean {
        return password == "1234"
    }

    private fun goToHome() {
        startActivity(Intent(this, HomeActivity::class.java))
        finish()
    }
}

class HomeActivity : AppCompatActivity() {
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_home)

        val logoutButton: Button = findViewById(R.id.logoutButton)
        logoutButton.setOnClickListener {
            AuthPrefs(this).clearAuthentication()
            startActivity(Intent(this, LoginActivity::class.java))
            finish()
        }
    }
}